-- AcadTrack Pro — 03_data.sql
-- Students: 508 | Grades: 23701
-- Sem Status: 4064 | Backlog Attempts: 232
-- Password = Roll Number for all students
-- Run THIRD after 02_seeds.sql
-- ════════════════════════════════════════════════════════

USE acadtrack_pro;
SET FOREIGN_KEY_CHECKS = 0;

-- ── Students (508 rows) ──────────────────────────

-- ── Grades (23701 rows) ────────────────────────────
















































-- ── Student_Semester_Status (4064 rows) ───────────









-- ── Backlog_Attempts (232 rows) ──────────────────

-- ── Fix credits_earned ──────────────────────────────
UPDATE students st
SET credits_earned = (
    SELECT COALESCE(SUM(sub.credits), 0)
    FROM grades g
    JOIN subjects sub ON g.subject_id = sub.subject_id
    WHERE g.student_id = st.student_id
    AND g.grade != 'F' AND sub.credits > 0
);

-- ── Replace invalid F grades (no backlog chain) ─────
UPDATE grades g
JOIN (
    SELECT grade_id, FLOOR(50 + RAND() * 50) AS new_marks
    FROM grades
    WHERE grade = 'F'
    AND NOT EXISTS (
        SELECT 1 FROM backlog_attempts ba
        WHERE ba.student_id = grades.student_id
        AND ba.subject_id = grades.subject_id
    )
) AS tmp ON g.grade_id = tmp.grade_id
SET g.marks = tmp.new_marks,
    g.grade = CASE
        WHEN tmp.new_marks >= 80 THEN 'A'
        WHEN tmp.new_marks >= 70 THEN 'B'
        WHEN tmp.new_marks >= 60 THEN 'C'
        ELSE 'D'
    END;

SET FOREIGN_KEY_CHECKS = 1;

-- ── Verify ──────────────────────────────────────────
SELECT 'students' AS tbl, COUNT(*) AS total FROM students
UNION ALL SELECT 'grades', COUNT(*) FROM grades
UNION ALL SELECT 'student_semester_status', COUNT(*) FROM student_semester_status
UNION ALL SELECT 'backlog_attempts', COUNT(*) FROM backlog_attempts;